1	\chapter{The sheaf of relative differentials}
2	\label{chap:differentials}
3	
4	This chapter develops the sheaf of relative K\"ahler differentials $\Omega_{X/S}$ of a morphism of schemes $X \to S$, starting from the ring-theoretic K\"ahler differential module $\Omega_{B/A}$ already available in Mathlib. The output is a quasi-coherent sheaf of $\struct{X}$-modules characterised by its restriction to affine opens: for any affine open $V = \Spec B \subseteq X$ lying over an affine open $U = \Spec A \subseteq S$, the sections satisfy
5	\[
6	  \Omega_{X/S}(V) \;=\; \Omega_{B/A}.
7	\]
8	
9	The downstream role of this chapter is twofold. First, the smoothness hypothesis on the curve $C \to \Spec k$ that appears in the Jacobian definition and the Abel--Jacobi map amounts to the condition that $\Omega_{C/k}$ is locally free of rank one; this characterisation is what unlocks the dimension computation $g(C) = \dim_k H^0(C, \Omega_{C/k}) = \dim_k H^1(C, \struct{C})$. Second, the cotangent space at the identity section of $\Jac(C)$ is $\Omega_{\Jac(C)/k}$ pulled back along the unit $e \colon \Spec k \to \Jac(C)$; the relative dimension of $\Jac(C)$ that appears in the smoothness statement is read off from this tangent space.
10	
11	\section{The relative cotangent sheaf}
12	
13	\begin{definition}\leanok
14	[Relative cotangent presheaf of a morphism]
15	  \label{def:relative_kaehler_presheaf}
16	  \lean{AlgebraicGeometry.Scheme.relativeDifferentialsPresheaf}
17	  Let $f \colon X \to S$ be a morphism of schemes. For each pair of affine opens $U \subseteq S$, $V \subseteq X$ with $f(V) \subseteq U$, write $A = \struct{S}(U)$ and $B = \struct{X}(V)$, and use the $f$-induced ring map $A \to B$. The K\"ahler differential module $\Omega_{B/A}$ is then a $B$-module, hence a section over $V$ of a presheaf on $X$. The collection of these modules, together with the natural restriction maps along inclusions of affine opens, defines a presheaf of $\struct{X}$-modules on $X$.
18	\end{definition}
19	
20	\begin{theorem}\leanok
21	[Sheaf condition for $\Omega_{X/S}$]
22	  \label{thm:relative_kaehler_isSheaf}
23	  \lean{AlgebraicGeometry.Scheme.relativeDifferentialsPresheaf_isSheaf}
24	  \uses{def:relative_kaehler_presheaf}
25	  The relative cotangent presheaf is a sheaf in the Zariski topology on $X$.
26	\end{theorem}
27	
28	\begin{proof}
29	  \uses{def:relative_kaehler_presheaf}
30	  \leanok
31	  The proof proceeds in three steps: reduction of the sheaf-of-modules condition to a sheaf-of-types condition; verification of the sheaf condition restricted to the affine basis via identification with the quasi-coherent module sheaf $\widetilde{\Omega_{B/A}}$ on each affine $V = \Spec B \subseteq X$; and gluing the affine-restricted sheaf condition along an affine cover of $X$.
32	
33	  \emph{Step 1: Reduction to a sheaf-of-types statement.} The sheaf condition for a presheaf valued in a concrete category lifts through any limit-preserving, isomorphism-reflecting forgetful functor: this is \texttt{TopCat.Presheaf.isSheaf\_iff\_isSheaf\_comp} [verified] (\texttt{Mathlib.Topology.Sheaves.Forget}). Apply it to the composite forgetful chain
34	  \[
35	    \mathrm{ModuleCat}\,\struct{X} \longrightarrow \mathrm{AddCommGrp} \longrightarrow \mathrm{Type},
36	  \]
37	  whose composite preserves limits and reflects isomorphisms because each factor does. After this reduction it suffices to verify the sheaf condition on the underlying sheaf-of-types of $\mathrm{relativeDifferentialsPresheaf}\,f$.
38	
39	  \emph{Step 2: Affine-restricted sheaf condition via $\widetilde{\Omega_{B/A}}$.} Fix an affine open $V = \Spec B \subseteq X$ lying over $U = \Spec A \subseteq S$. The ring-level structure map is $A \to B$; the relative-differentials presheaf assigns to a basic open $D(f) \subseteq V$ (for $f \in B$) the K\"ahler differential module $\Omega_{B[1/f]/A}$, with $B[1/f] \cong \Gamma(V, V.\mathrm{basicOpen}\,f)$ obtained from \texttt{AlgebraicGeometry.IsAffineOpen.isLocalization\_basicOpen} [verified] (\texttt{Mathlib.AlgebraicGeometry.AffineScheme}).
40	
41	  Mathlib's \texttt{KaehlerDifferential.isLocalizedModule\_map} [verified] (\texttt{Mathlib.RingTheory.Etale.Kaehler}, line~63) is an instance asserting: for any commutative-ring tower $A \to B \to T$ with $T = B[M^{-1}]$ for a multiplicative submonoid $M \subseteq B$, the canonical $B$-linear map $\Omega_{B/A} \to \Omega_{T/A}$ exhibits $\Omega_{T/A}$ as the localisation of $\Omega_{B/A}$ at $M$, i.e.\ as an \texttt{IsLocalizedModule}. Applied with $M = \mathrm{Submonoid.powers}\,f$ and $T = B[1/f]$, this gives the canonical $B[1/f]$-linear isomorphism
42	  \[
43	    \Omega_{B/A} \otimes_B B[1/f] \;\xrightarrow{\;\sim\;}\; \Omega_{B[1/f]/A}, \qquad b \otimes \omega \mapsto b \cdot (\mathrm{map}_{A,A,B,B[1/f]}\,\omega),
44	  \]
45	  obtained as the universal map associated to the \texttt{IsLocalizedModule} structure. (Equivalently, the bare existence of this iso is also packaged as the linear equivalence \texttt{KaehlerDifferential.tensorKaehlerEquivOfFormallyEtale} [verified] applied to $R = A$, $S = B$, $T = B[1/f]$, valid because $B \to B[1/f]$ is formally \'etale by \texttt{Algebra.FormallyEtale.of\_isLocalization} [verified] (\texttt{Mathlib.RingTheory.Etale.Basic}, line~190). The bare name \texttt{KaehlerDifferential.tensorKaehlerEquiv}, whose signature requires an \texttt{Algebra.IsPushout} hypothesis, is not the right entry point in this setting.) This is the content of Stacks Tag~01UM and Hartshorne~II.8, Proposition~8.2A: K\"ahler differentials commute with localisation.
46	
47	  Under this identification, the assignment $D(f) \mapsto \Omega_{B[1/f]/A}$ on the basis of basic opens of $V = \Spec B$ coincides — pointwise as a $B$-module — with the assignment $D(f) \mapsto (\Omega_{B/A})[1/f]$ that defines Mathlib's quasi-coherent module sheaf $\widetilde{\Omega_{B/A}}$. The latter is by construction a sheaf of $\struct{V}$-modules on $V = \Spec B$: this is \texttt{AlgebraicGeometry.Modules.tilde} [verified] (\texttt{Mathlib.AlgebraicGeometry.Modules.Tilde}, line~87), whose \texttt{isSheaf} field provides the sheaf property as part of the construction (internally via \texttt{TopCat.Presheaf.isSheaf\_iff\_isSheaf\_comp} applied to \texttt{structureSheafInType}). In particular, no separate equalizer-products-on-a-finite-cover verification is needed at this step: it is absorbed into the sheaf property of $\widetilde{\Omega_{B/A}}$.
48	
49	  \emph{Step 3: Globalising across an affine cover of $X$.} The scheme $X$ admits an affine open cover, e.g.\ the canonical basis \texttt{AlgebraicGeometry.Scheme.isBasis\_affineOpens} [verified] (\texttt{Mathlib.AlgebraicGeometry.AffineScheme}). On each affine $V_\alpha = \Spec B_\alpha \subseteq X$ over some $U_\alpha = \Spec A_\alpha \subseteq S$, Step~2 identifies the restriction of $\mathrm{relativeDifferentialsPresheaf}\,f$ to the basis of basic opens of $V_\alpha$ with the sheaf $\widetilde{\Omega_{B_\alpha/A_\alpha}}|_{V_\alpha}$. To deduce the sheaf condition on all of $X$, one verifies the \emph{open-le-cover} characterisation \texttt{TopCat.Presheaf.isSheaf\_iff\_isSheafOpensLeCover} [verified] (\texttt{Mathlib.Topology.Sheaves.SheafCondition.OpensLeCover}), or equivalently the \emph{pairwise-intersections} characterisation \texttt{TopCat.Presheaf.isSheaf\_iff\_isSheafPairwiseIntersections} [verified] (\texttt{Mathlib.Topology.Sheaves.SheafCondition.PairwiseIntersections}, line~280), or the \emph{equalizer-products} characterisation \texttt{TopCat.Presheaf.isSheaf\_iff\_isSheafEqualizerProducts} [verified] (\texttt{Mathlib.Topology.Sheaves.SheafCondition.EqualizerProducts}). The argument is: given an arbitrary open $W \subseteq X$ and an open cover $\{W_\beta\}$ of $W$, refine the cover by intersecting each $W_\beta$ with the affine basis, obtaining a refined cover by basic opens of affine charts; the equalizer-products condition for this refined cover follows from the affine-restricted sheaf property established in Step~2, and the equalizer-products condition on the original cover follows from that on the refinement by the cofinality of the refinement in the opens-le-cover category.
50	
51	  \textbf{[gap]} No direct off-the-shelf ``sheaf-on-affine-basis-of-a-Scheme $\Rightarrow$ sheaf'' theorem is currently in Mathlib for $\mathrm{Scheme.PresheafOfModules}$: the search located neither a \texttt{TopCat.SheafOnBasis}-style framework nor a packaged ``glue an affine cover of sheaves on affine opens into a sheaf on $X$'' lemma. The prover must therefore either (a) write the refinement-cofinality argument explicitly against \texttt{isSheaf\_iff\_isSheafOpensLeCover}, treating an arbitrary cover by intersecting with the affine basis and lifting the affine-restricted equalizer-products condition, or (b) build the global sheaf as the gluing of the affine pieces $\widetilde{\Omega_{B_\alpha/A_\alpha}}$ along the overlaps $V_\alpha \cap V_\beta$ and identify it with $\mathrm{relativeDifferentialsPresheaf}\,f$ on sections. Route~(b) is morally cleaner but requires an explicit gluing construction; Route~(a) is the route the Lean stub in \texttt{AlgebraicGeometry.Scheme.relativeDifferentialsPresheaf\_isSheaf} contemplates (Differentials.lean, lines~113--122). \emph{Either route is mathematically standard but is not pinned to a single named Mathlib lemma}; the prover is expected to construct the descent step.
52	
53	  We note explicitly that the alternative route through \texttt{SheafOfModules.IsQuasicoherent} is not viable: that abstraction packages a sheaf of modules together with its quasi-coherent local description, but it requires the underlying presheaf to already be a sheaf — which is precisely the statement we are proving. We also note that the previous draft of this proof cited \texttt{TopCat.Presheaf.IsSheaf.isSheafUniqueGluing} as a basis-to-opens hook; that direction is wrong (it converts a finished \texttt{IsSheaf} proof into a \texttt{IsSheafUniqueGluing} predicate), and the present rewrite removes that reference.
54	\end{proof}
55	
56	\begin{definition}\leanok
57	[Relative cotangent sheaf $\Omega_{X/S}$]
58	  \label{def:relative_kaehler_sheaf}
59	  \lean{AlgebraicGeometry.Scheme.relativeDifferentials}
60	  \uses{def:relative_kaehler_presheaf, thm:relative_kaehler_isSheaf}
61	  The sheaf of $\struct{X}$-modules associated with the relative cotangent presheaf is the \emph{sheaf of relative differentials} $\Omega_{X/S}$. It is quasi-coherent.
62	\end{definition}
63	
64	\begin{remark}[Comparison with Mathlib's ring-level $\Omega_{B/A}$]
65	  \label{rem:kahler_compatibility}
66	  Mathlib provides the ring-theoretic K\"ahler differential module $\Omega_{B/A}$ together with the universal derivation $\mathrm{d} \colon B \to \Omega_{B/A}$. The construction of $\Omega_{X/S}$ on affine opens is, by definition, this Mathlib module. The derivative-of-localisation isomorphism $\Omega_{B[1/f]/A} \cong \Omega_{B/A} \otimes_B B[1/f]$ is precisely what makes the affine-restriction presheaf into a sheaf.
67	\end{remark}
